"use client";

import { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Plus, Search, Filter, Edit2, Trash2, ExternalLink, FileText, Tag } from "lucide-react";
import Image from "next/image";
import Link from "next/link";
import { GlassCard } from "@/components/ui/GlassCard";
import { cn } from "@/lib/utils";
import { BlogForm } from "@/components/admin/BlogForm";
import { createClient } from "@/lib/supabase";
import { useRouter } from "next/navigation";


export default function BlogsPage() {
    const [search, setSearch] = useState("");
    const [blogs, setBlogs] = useState<any[]>([]);
    const [isFormOpen, setIsFormOpen] = useState(false);
    const [editingBlog, setEditingBlog] = useState<any>(null);
    const [isHydrated, setIsHydrated] = useState(false);

    const supabase = createClient();
    const router = useRouter();

    // Fetch blogs from Supabase
    const fetchBlogs = async () => {
        const { data, error } = await supabase
            .from('blogs')
            .select(`
                *,
                profiles:author_id (full_name)
            `)
            .order('created_at', { ascending: false });

        if (error) {
            console.error("Error fetching blogs:", error);
        } else if (data) {
            const getValidUrl = (url: any) => {
                if (!url || typeof url !== 'string') return "/placeholder.jpg";
                if (url.startsWith('/')) return url;
                if (url.startsWith('http')) return url;
                return "/placeholder.jpg";
            };

            // Map DB fields to UI fields if necessary, but schema is close.
            // UI expects: id, title, excerpt, coverImage, author, readTime, date, status, slug, content
            // DB has: id, title, slug, content, image, author_id, created_at
            const mappedBlogs = data.map((blog: any) => ({
                id: blog.id,
                title: blog.title,
                excerpt: blog.content?.substring(0, 100).replace(/<[^>]*>?/gm, "") + "...", // Auto-excerpt
                coverImage: getValidUrl(blog.image),
                author: blog.profiles?.full_name || "Admin",
                readTime: "5 min", // Mock read time for now
                date: new Date(blog.created_at).toLocaleDateString(),
                status: "Published", // defaulting for now
                slug: blog.slug,
                content: blog.content
            }));
            setBlogs(mappedBlogs);
        }
        setIsHydrated(true);
    };

    useEffect(() => {
        fetchBlogs();
    }, []);

    const handleAdd = () => {
        setEditingBlog(null);
        setIsFormOpen(true);
    };

    const handleEdit = (blog: any) => {
        setEditingBlog(blog);
        setIsFormOpen(true);
    };

    const handleDelete = async (id: string) => {
        if (confirm("Are you sure you want to delete this story?")) {
            const { error } = await supabase.from('blogs').delete().eq('id', id);
            if (!error) {
                setBlogs(prev => prev.filter(b => b.id !== id));
            } else {
                alert("Error deleting blog: " + error.message);
            }
        }
    };

    const handleFormSubmit = (data: any) => {
        // Form handles DB internally now, just refresh
        fetchBlogs();
        setIsFormOpen(false);
    };

    const filteredBlogs = blogs.filter(b =>
        b.title.toLowerCase().includes(search.toLowerCase()) ||
        b.id.toLowerCase().includes(search.toLowerCase())
    );

    if (!isHydrated) return null;

    return (
        <div className="space-y-8">
            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-end gap-6">
                <div>
                    <h1 className="text-2xl md:text-3xl font-bold">Editorial Manager</h1>
                    <p className="text-zinc-500 text-sm mt-1">Craft and manage your brand stories.</p>
                </div>
                <div className="flex items-center gap-4">
                    <Link
                        href="/admin/blog-categories"
                        className="flex items-center gap-2 px-6 py-3 glass rounded-xl font-bold hover:bg-white/5 transition-all active:scale-95 text-sm"
                    >
                        <Tag className="w-4 h-4 text-zinc-400" />
                        Categories
                    </Link>
                    <button
                        onClick={handleAdd}
                        className="flex items-center gap-2 px-6 py-3 bg-white text-black rounded-xl font-bold hover:bg-zinc-200 transition-all active:scale-95 w-full sm:w-auto justify-center text-sm shadow-xl shadow-white/5"
                    >
                        <Plus className="w-4 h-4" />
                        New Story
                    </button>
                </div>
            </div>

            <div className="relative w-full sm:w-96">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-zinc-500" />
                <input
                    value={search}
                    onChange={(e) => setSearch(e.target.value)}
                    placeholder="Search Stories..."
                    className="bg-[#050505] border border-white/5 rounded-lg py-2 pl-10 pr-4 outline-none focus:border-blue-500/50 transition-all text-xs w-full"
                />
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                <AnimatePresence mode="popLayout">
                    {filteredBlogs.map((blog, i) => (
                        <motion.div
                            key={blog.id}
                            layout
                            initial={{ opacity: 0, y: 20 }}
                            animate={{ opacity: 1, y: 0 }}
                            exit={{ opacity: 0, scale: 0.95 }}
                            transition={{ delay: i * 0.05 }}
                        >
                            <GlassCard className="p-0 overflow-hidden border-white/5 group h-full flex flex-col">
                                <div className="relative h-48 w-full overflow-hidden">
                                    <Image
                                        src={blog.coverImage}
                                        alt={blog.title}
                                        fill
                                        className="object-cover transition-transform duration-700 group-hover:scale-110"
                                    />
                                    <div className="absolute inset-0 bg-gradient-to-t from-black/80 to-transparent" />
                                    <div className="absolute top-4 right-4 flex gap-2">
                                        <button
                                            onClick={() => handleEdit(blog)}
                                            className="p-2 bg-white/10 backdrop-blur-md rounded-lg text-white hover:bg-white/20 transition-all"
                                        >
                                            <Edit2 className="w-4 h-4" />
                                        </button>
                                        <button
                                            onClick={() => handleDelete(blog.id)}
                                            className="p-2 bg-red-500/10 backdrop-blur-md rounded-lg text-red-400 hover:bg-red-500/20 transition-all"
                                        >
                                            <Trash2 className="w-4 h-4" />
                                        </button>
                                    </div>
                                    <div className="absolute bottom-4 left-4">
                                        <span className="text-[8px] uppercase tracking-widest font-black bg-blue-500 px-2 py-1 rounded">
                                            {blog.status}
                                        </span>
                                    </div>
                                </div>
                                <div className="p-6 flex-1 flex flex-col">
                                    <div className="flex items-center gap-2 text-[10px] text-zinc-500 font-bold uppercase tracking-widest mb-2">
                                        <span>{blog.date}</span>
                                        <span>•</span>
                                        <span>{blog.readTime}</span>
                                    </div>
                                    <h3 className="text-lg font-bold group-hover:text-blue-400 transition-colors mb-2 line-clamp-2">
                                        {blog.title}
                                    </h3>
                                    <p className="text-zinc-500 text-xs line-clamp-3 mb-6">
                                        {blog.excerpt}
                                    </p>
                                    <div className="mt-auto pt-6 border-t border-white/5 flex items-center justify-between">
                                        <div className="flex items-center gap-2">
                                            <div className="w-6 h-6 rounded-full glass flex items-center justify-center text-[10px] font-bold text-blue-400">
                                                {blog.author[0]}
                                            </div>
                                            <span className="text-[10px] text-zinc-400 font-bold uppercase tracking-widest">{blog.author}</span>
                                        </div>
                                        <ExternalLink className="w-4 h-4 text-zinc-600" />
                                    </div>
                                </div>
                            </GlassCard>
                        </motion.div>
                    ))}
                </AnimatePresence>
            </div>

            <BlogForm
                isOpen={isFormOpen}
                onClose={() => setIsFormOpen(false)}
                onSubmit={handleFormSubmit}
                initialData={editingBlog}
            />
        </div>
    );
}

"use client";

import { useState, useEffect } from "react";
import { createClient } from "@/lib/supabase";
import { motion, AnimatePresence } from "framer-motion";
import { Users, Search, MapPin, ShoppingBag, ChevronDown, ChevronUp, Phone, Mail } from "lucide-react";
import { GlassCard } from "@/components/ui/GlassCard";
import { format } from "date-fns";

interface Customer {
    id: string; // user_id
    email: string | null;
    role: string;
    created_at: string;
    orders: any[];
    addresses: any[];
    totalSpent: number;
}

export default function AdminCustomersPage() {
    const [customers, setCustomers] = useState<Customer[]>([]);
    const [loading, setLoading] = useState(true);
    const [expandedCustomer, setExpandedCustomer] = useState<string | null>(null);
    const [searchTerm, setSearchTerm] = useState("");

    const supabase = createClient();

    useEffect(() => {
        fetchCustomers();
    }, []);

    const fetchCustomers = async () => {
        setLoading(true);
        try {
            // 1. Fetch Profiles (Base of our customer list)
            const { data: profiles, error: profileError } = await supabase
                .from('profiles')
                .select('*')
                .order('created_at', { ascending: false });

            if (profileError) throw profileError;

            // 2. Fetch Orders
            const { data: orders, error: orderError } = await supabase
                .from('orders')
                .select('*');

            if (orderError) throw orderError;

            // 3. Fetch Addresses
            const { data: addresses, error: addressError } = await supabase
                .from('addresses')
                .select('*');

            if (addressError) throw addressError;

            // 4. Aggregation Logic
            const aggregatedCustomers = profiles.map((profile: any) => {
                const userOrders = orders?.filter((o: any) => o.user_id === profile.id) || [];
                const userAddresses = addresses?.filter((a: any) => a.user_id === profile.id) || [];

                const totalSpent = userOrders.reduce((acc: number, curr: any) => {
                    return acc + (parseFloat(curr.total_amount) || 0);
                }, 0);

                return {
                    id: profile.id,
                    email: profile.email,
                    role: profile.role,
                    created_at: profile.created_at,
                    orders: userOrders,
                    addresses: userAddresses,
                    totalSpent
                };
            });

            setCustomers(aggregatedCustomers);

        } catch (error) {
            console.error("Error fetching customers:", error);
        } finally {
            setLoading(false);
        }
    };

    const toggleExpand = (id: string) => {
        setExpandedCustomer(expandedCustomer === id ? null : id);
    };

    const filteredCustomers = customers.filter(c =>
        c.email?.toLowerCase().includes(searchTerm.toLowerCase()) ||
        c.id.includes(searchTerm)
    );

    return (
        <div className="space-y-8 pb-20">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                <div>
                    <h1 className="text-3xl font-bold">Sanctuary Members</h1>
                    <p className="text-zinc-500 mt-1">Manage and view your customer base.</p>
                </div>

                <div className="relative group w-full md:w-72">
                    <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-zinc-500 group-focus-within:text-blue-400 transition-colors" />
                    <input
                        type="text"
                        placeholder="Search by email..."
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                        className="w-full bg-white/5 border border-white/10 rounded-full py-2 pl-12 pr-4 outline-none focus:border-blue-500/50 focus:bg-white/10 transition-all text-sm"
                    />
                </div>
            </div>

            {loading ? (
                <div className="text-center py-20 text-zinc-500 animate-pulse">Summoning spirits...</div>
            ) : (
                <div className="space-y-4">
                    {filteredCustomers.map((customer) => (
                        <GlassCard key={customer.id} className="overflow-hidden transition-all duration-500 border-white/5 hover:border-white/10">
                            <div
                                onClick={() => toggleExpand(customer.id)}
                                className="p-6 flex items-center justify-between cursor-pointer hover:bg-white/[0.02] transition-colors"
                            >
                                <div className="flex items-center gap-4 md:gap-6">
                                    <div className={`w-10 h-10 rounded-full flex items-center justify-center font-bold text-sm ${customer.role === 'admin' ? 'bg-purple-500/20 text-purple-400' : 'bg-blue-500/20 text-blue-400'}`}>
                                        {customer.email ? customer.email[0].toUpperCase() : <Users className="w-5 h-5" />}
                                    </div>
                                    <div>
                                        <h3 className="font-bold text-sm md:text-base">{customer.email || "Unknown Spirit"}</h3>
                                        <p className="text-xs text-zinc-500 uppercase tracking-widest mt-0.5">
                                            Joined {format(new Date(customer.created_at), 'MMM dd, yyyy')}
                                        </p>
                                    </div>
                                </div>

                                <div className="flex items-center gap-6 md:gap-12">
                                    <div className="text-right hidden sm:block">
                                        <p className="text-[10px] text-zinc-500 uppercase tracking-widest font-bold">Orders</p>
                                        <p className="font-mono text-sm">{customer.orders.length}</p>
                                    </div>
                                    <div className="text-right hidden sm:block">
                                        <p className="text-[10px] text-zinc-500 uppercase tracking-widest font-bold">Spend</p>
                                        <p className="font-mono text-sm text-green-400">${customer.totalSpent.toFixed(2)}</p>
                                    </div>
                                    <div>
                                        {expandedCustomer === customer.id ? <ChevronUp className="w-5 h-5 text-zinc-500" /> : <ChevronDown className="w-5 h-5 text-zinc-500" />}
                                    </div>
                                </div>
                            </div>

                            <AnimatePresence>
                                {expandedCustomer === customer.id && (
                                    <motion.div
                                        initial={{ height: 0, opacity: 0 }}
                                        animate={{ height: "auto", opacity: 1 }}
                                        exit={{ height: 0, opacity: 0 }}
                                        className="border-t border-white/5 bg-black/20"
                                    >
                                        <div className="p-6 grid grid-cols-1 lg:grid-cols-2 gap-8">
                                            {/* Addresses Section */}
                                            <div className="space-y-4">
                                                <div className="flex items-center gap-2 text-zinc-400 border-b border-white/10 pb-2">
                                                    <MapPin className="w-4 h-4" />
                                                    <h4 className="text-xs font-bold uppercase tracking-widest">Address Book</h4>
                                                </div>
                                                {customer.addresses.length > 0 ? (
                                                    <div className="space-y-3">
                                                        {customer.addresses.map(addr => (
                                                            <div key={addr.id} className="text-sm bg-white/5 p-3 rounded-lg border border-white/5">
                                                                <p className="font-bold text-white mb-1">{addr.name}</p>
                                                                <p className="text-zinc-400 text-xs leading-relaxed">
                                                                    {addr.street}<br />
                                                                    {addr.city}, {addr.state} - {addr.pincode}
                                                                </p>
                                                                <div className="flex items-center gap-2 mt-2 text-xs text-zinc-500">
                                                                    <Phone className="w-3 h-3" />
                                                                    {addr.phone}
                                                                </div>
                                                            </div>
                                                        ))}
                                                    </div>
                                                ) : (
                                                    <p className="text-zinc-600 text-sm italic">No addresses saved yet.</p>
                                                )}
                                            </div>

                                            {/* Recent Orders Section */}
                                            <div className="space-y-4">
                                                <div className="flex items-center gap-2 text-zinc-400 border-b border-white/10 pb-2">
                                                    <ShoppingBag className="w-4 h-4" />
                                                    <h4 className="text-xs font-bold uppercase tracking-widest">Recent Orders</h4>
                                                </div>
                                                {customer.orders.length > 0 ? (
                                                    <div className="space-y-3">
                                                        {customer.orders.slice(0, 5).map(order => (
                                                            <div key={order.id} className="flex justify-between items-center text-sm bg-white/5 p-3 rounded-lg border border-white/5">
                                                                <div>
                                                                    <p className="font-mono text-xs text-zinc-500 mb-1">#{order.id.slice(0, 8)}</p>
                                                                    <div className={`text-[10px] px-2 py-0.5 rounded-full w-fit ${order.status === 'paid' ? 'bg-green-500/20 text-green-400' :
                                                                            order.status === 'pending' ? 'bg-yellow-500/20 text-yellow-400' :
                                                                                'bg-red-500/20 text-red-400'
                                                                        }`}>
                                                                        {order.status.toUpperCase()}
                                                                    </div>
                                                                </div>
                                                                <div className="text-right">
                                                                    <p className="font-bold md:text-base">${order.total_amount}</p>
                                                                    <p className="text-[10px] text-zinc-500">{format(new Date(order.created_at), 'MMM dd')}</p>
                                                                </div>
                                                            </div>
                                                        ))}
                                                    </div>
                                                ) : (
                                                    <p className="text-zinc-600 text-sm italic">No orders placed yet.</p>
                                                )}
                                            </div>
                                        </div>
                                    </motion.div>
                                )}
                            </AnimatePresence>
                        </GlassCard>
                    ))}

                    {filteredCustomers.length === 0 && (
                        <div className="text-center py-20 text-zinc-500">
                            <p>No spirits found matching your query.</p>
                        </div>
                    )}
                </div>
            )}
        </div>
    );
}

"use client";

import { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Plus, Search, Filter, Edit2, Trash2, ExternalLink } from "lucide-react";
import Image from "next/image";
import { GlassCard } from "@/components/ui/GlassCard";
import { cn } from "@/lib/utils";
import { createClient } from "@/lib/supabase";
import { ProductForm } from "@/components/admin/ProductForm";
import { CategoryForm } from "@/components/admin/CategoryForm";
import { useRouter } from "next/navigation";


export default function InventoryPage() {
    const [search, setSearch] = useState("");
    const [inventory, setInventory] = useState<any[]>([]);
    const [categories, setCategories] = useState<string[]>([]);
    const [isFormOpen, setIsFormOpen] = useState(false);
    const [isCatFormOpen, setIsCatFormOpen] = useState(false);
    const [editingProduct, setEditingProduct] = useState<any>(null);
    const [editingCategory, setEditingCategory] = useState<any>(null);
    const [selectedCategory, setSelectedCategory] = useState("All");
    const [activeTab, setActiveTab] = useState<"products" | "categories">("products");
    const [isHydrated, setIsHydrated] = useState(false);

    const supabase = createClient();
    const router = useRouter();

    // Fetch data from Supabase
    const fetchData = async () => {
        const { data: products, error: prodError } = await supabase
            .from('products')
            .select('*')
            .order('created_at', { ascending: false });

        if (products) setInventory(products);
        if (prodError) console.error("Error fetching products:", prodError);

        const { data: cats, error: catError } = await supabase
            .from('categories')
            .select('name')
            .order('name');

        if (cats) setCategories(cats.map((c: any) => c.name));
        if (catError) console.error("Error fetching categories:", catError);

        setIsHydrated(true);
    };

    useEffect(() => {
        fetchData();
    }, []);

    // Refresh data after updates
    const handleRefresh = () => {
        fetchData();
    };

    // Remove legacy localStorage effects

    const handleAdd = () => {
        setEditingProduct(null);
        setIsFormOpen(true);
    };

    const handleEdit = (product: any) => {
        setEditingProduct(product);
        setIsFormOpen(true);
    };

    const handleAddCategory = () => {
        setEditingCategory(null);
        setIsCatFormOpen(true);
    };

    const handleEditCategory = (name: string) => {
        setEditingCategory({ name });
        setIsCatFormOpen(true);
    };

    const handleCategorySubmit = (name: string) => {
        if (editingCategory) {
            const oldName = editingCategory.name;
            setCategories(prev => prev.map(c => c === oldName ? name : c));
            setCategories(prev => prev.map(c => c === oldName ? name : c));
            setInventory(prev => prev.map(p => {
                const newCategories = p.categories ? p.categories.map((c: string) => c === oldName ? name : c) : [];
                // Handle legacy category field update as well if it matches
                const newCategory = p.category === oldName ? name : p.category;
                return { ...p, category: newCategory, categories: newCategories.length ? newCategories : (p.category === oldName ? [name] : []) };
            }));
        } else {
            if (!categories.includes(name)) {
                setCategories(prev => [...prev, name]);
            }
        }
    };

    const handleDeleteCategory = async (name: string) => {
        const count = inventory.filter(p => p.categories?.includes(name) || p.category === name).length;
        if (confirm(`Deleting this category will leave ${count} producs uncategorized. Proceed?`)) {
            // Real deletion logic needed for DB, for now we just UI update but ideally we delete row
            // But category deletion is complex due to FK.
            // Simplification: We only delete from UI state for now, but implementation below
            const { error } = await supabase.from('categories').delete().eq('name', name);
            if (!error) handleRefresh();
        }
    };

    const handleDelete = async (id: string) => {
        if (confirm("Are you sure you want to delete this product?")) {
            const { error } = await supabase.from('products').delete().eq('id', id);
            if (!error) {
                setInventory(prev => prev.filter(p => p.id !== id));
            } else {
                console.error("Delete error:", error);
                alert(`Error deleting product: ${error.message}`);
            }
        }
    };

    const handleFormSubmit = (data: any) => {
        // Form now handles submission internally via prop, but we need to refresh
        handleRefresh();
        setIsFormOpen(false);
    };

    const handleCategoryFormSubmit = () => {
        handleRefresh();
        setIsCatFormOpen(false);
    }

    const filteredInventory = inventory.filter(p =>
        (p.name.toLowerCase().includes(search.toLowerCase()) || p.id.toLowerCase().includes(search.toLowerCase())) &&
        (selectedCategory === "All" || p.categories?.includes(selectedCategory) || p.category === selectedCategory)
    );

    const filteredCategories = categories.filter(c => c.toLowerCase().includes(search.toLowerCase()));

    if (!isHydrated) return null; // Prevent hydration mismatch

    return (
        <div className="space-y-8">
            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-end gap-6">
                <div>
                    <h1 className="text-2xl md:text-3xl font-bold">Inventory Manager</h1>
                    <p className="text-zinc-500 text-sm mt-1">Manage your product catalog and categories.</p>
                </div>
                <div className="flex gap-3 w-full sm:w-auto">
                    <div className="flex bg-white/5 p-1 rounded-xl border border-white/5">
                        <button
                            onClick={() => setActiveTab("products")}
                            className={cn(
                                "px-4 py-2 rounded-lg text-xs font-bold uppercase tracking-widest transition-all",
                                activeTab === "products" ? "bg-white text-black shadow-lg" : "text-zinc-500 hover:text-white"
                            )}
                        >
                            Products
                        </button>
                        <button
                            onClick={() => setActiveTab("categories")}
                            className={cn(
                                "px-4 py-2 rounded-lg text-xs font-bold uppercase tracking-widest transition-all",
                                activeTab === "categories" ? "bg-white text-black shadow-lg" : "text-zinc-500 hover:text-white"
                            )}
                        >
                            Categories
                        </button>
                    </div>
                </div>
            </div>

            <div className="flex flex-col sm:flex-row justify-between items-center gap-4">
                <div className="flex flex-col sm:flex-row items-stretch sm:items-center gap-4 w-full sm:w-auto">
                    <div className="relative flex-1 sm:flex-initial">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-zinc-500" />
                        <input
                            value={search}
                            onChange={(e) => setSearch(e.target.value)}
                            placeholder={activeTab === "products" ? "Search Products..." : "Filter Categories..."}
                            className="bg-[#050505] border border-white/5 rounded-lg py-2 pl-10 pr-4 outline-none focus:border-blue-500/50 transition-all text-xs w-full sm:w-64"
                        />
                    </div>
                    {activeTab === "products" && (
                        <div className="relative flex-1 sm:flex-initial">
                            <Filter className="absolute left-3 top-1/2 -translate-y-1/2 w-3 h-3 text-zinc-500" />
                            <select
                                value={selectedCategory}
                                onChange={(e) => setSelectedCategory(e.target.value)}
                                className="w-full bg-[#050505] border border-white/5 rounded-lg py-2 pl-10 pr-8 outline-none focus:border-blue-500/50 transition-all text-[10px] font-bold uppercase tracking-widest appearance-none"
                            >
                                <option value="All">All Categories</option>
                                {categories.map(cat => (
                                    <option key={cat} value={cat}>{cat}</option>
                                ))}
                            </select>
                        </div>
                    )}
                </div>

                <button
                    onClick={activeTab === "products" ? handleAdd : handleAddCategory}
                    className="flex items-center gap-2 px-6 py-3 bg-white text-black rounded-xl font-bold hover:bg-zinc-200 transition-all active:scale-95 w-full sm:w-auto justify-center text-sm shadow-xl shadow-white/5"
                >
                    <Plus className="w-4 h-4" />
                    {activeTab === "products" ? "New Product" : "New Category"}
                </button>
            </div>

            <AnimatePresence mode="wait">
                {activeTab === "products" ? (
                    <motion.div
                        key="products"
                        initial={{ opacity: 0, y: 10 }}
                        animate={{ opacity: 1, y: 0 }}
                        exit={{ opacity: 0, y: -10 }}
                    >
                        <GlassCard className="p-0 overflow-hidden border-white/5">
                            {/* Table Header */}
                            <div className="hidden lg:grid grid-cols-12 gap-4 px-8 py-4 text-[10px] font-bold uppercase tracking-[0.2em] text-zinc-400 bg-white/[0.02] border-b border-white/5">
                                <div className="col-span-1">Image</div>
                                <div className="col-span-4">Product Name</div>
                                <div className="col-span-2">Category</div>
                                <div className="col-span-1">Stock</div>
                                <div className="col-span-2">Price</div>
                                <div className="col-span-1">Status</div>
                                <div className="col-span-1 text-right">Actions</div>
                            </div>

                            {/* Table Body */}
                            <div className="divide-y divide-white/5">
                                <AnimatePresence mode="popLayout">
                                    {filteredInventory.map((item, i) => (
                                        <motion.div
                                            key={item.id}
                                            layout
                                            initial={{ opacity: 0, x: -10 }}
                                            animate={{ opacity: 1, x: 0 }}
                                            exit={{ opacity: 0, scale: 0.95 }}
                                            transition={{ delay: i * 0.05 }}
                                            className="flex flex-col lg:grid lg:grid-cols-12 gap-4 px-6 md:px-8 py-6 lg:py-5 items-start lg:items-center hover:bg-white/[0.03] transition-colors group relative"
                                        >
                                            <div className="lg:col-span-1 flex items-center justify-between w-full lg:w-auto">
                                                <div className="relative w-12 h-14 rounded-lg overflow-hidden border border-white/10 shrink-0 bg-white/5">
                                                    {item.image ? (
                                                        <Image src={item.image} alt={item.name} fill className="object-cover" />
                                                    ) : (
                                                        <div className="flex items-center justify-center h-full text-[8px] text-zinc-600 font-bold uppercase text-center">No Imagery</div>
                                                    )}
                                                </div>
                                                <div className="lg:hidden flex items-center gap-1">
                                                    <button onClick={() => handleEdit(item)} className="p-2 hover:bg-white/10 rounded-lg text-zinc-400 hover:text-blue-400 transition-all"><Edit2 className="w-4 h-4" /></button>
                                                    <button onClick={() => handleDelete(item.id)} className="p-2 hover:bg-white/10 rounded-lg text-zinc-400 hover:text-red-400 transition-all"><Trash2 className="w-4 h-4" /></button>
                                                </div>
                                            </div>
                                            <div className="lg:col-span-4 w-full">
                                                <p className="text-sm md:text-base lg:text-sm font-bold group-hover:text-blue-400 transition-colors uppercase tracking-wider">{item.name}</p>
                                                <p className="text-[10px] text-zinc-500 tracking-widest mt-1 font-mono">{item.id}</p>
                                            </div>
                                            <div className="lg:col-span-2 flex items-center gap-4 lg:gap-0 w-full lg:w-auto text-[10px] font-bold uppercase tracking-widest">
                                                <span className="lg:hidden text-zinc-500 w-16">Category:</span>
                                                <div className="flex flex-wrap gap-1">
                                                    {item.categories && item.categories.length > 0 ? (
                                                        item.categories.map((c: string) => (
                                                            <span key={c} className="glass px-3 py-1 rounded-full border-white/5 text-zinc-300">{c}</span>
                                                        ))
                                                    ) : (
                                                        <span className="glass px-3 py-1 rounded-full border-white/5 text-zinc-300">{item.category || "Uncategorized"}</span>
                                                    )}
                                                </div>
                                            </div>
                                            <div className="lg:col-span-1 flex items-center gap-4 lg:gap-0 w-full lg:w-auto font-mono text-xs">
                                                <span className="lg:hidden text-[10px] text-zinc-500 font-bold uppercase tracking-widest w-16">Stock:</span>
                                                {item.stock}
