import { NextResponse } from 'next/server';
import { Resend } from 'resend';

export const dynamic = 'force-dynamic';

export async function GET() {
    const key = process.env.RESEND_API_KEY;

    const status = {
        hasKey: !!key,
        keyPrefix: key ? key.substring(0, 4) + '...' : 'MISSING',
        env: process.env.NODE_ENV
    };

    if (!key) {
        return NextResponse.json({
            success: false,
            message: "CRITICAL: RESEND_API_KEY is missing from environment variables.",
            debug: status
        }, { status: 500 });
    }

    try {
        const resend = new Resend(key);
        const { data, error } = await resend.emails.send({
            from: 'We Naturals <orders@wenaturals.shop>',
            to: ['delivered@resend.dev'], // Safe test address
            subject: 'Diagnostic Test Email',
            html: '<p>If you received this, the email configuration is working.</p>'
        });

        if (error) {
            return NextResponse.json({
                success: false,
                message: "API Key exists but sending failed. Check domain verification.",
                error,
                debug: status
            }, { status: 400 });
        }

        return NextResponse.json({
            success: true,
            message: "Configuration valid. Test email sent to delivered@resend.dev",
            data,
            debug: status
        });

    } catch (e: any) {
        return NextResponse.json({
            success: false,
            message: "Unexpected error during send attempt.",
            error: e.message,
            debug: status
        }, { status: 500 });
    }
}

import { NextRequest, NextResponse } from "next/server";
import Razorpay from "razorpay";
import { createAdminClient } from "@/lib/supabase-admin";

export async function POST(req: NextRequest) {
    try {
        const body = await req.json();
        const { order_id } = body;

        console.log(`[PaymentAPI] Initiating order: ${order_id}`);

        if (!order_id) {
            return NextResponse.json({ error: "Order ID is required" }, { status: 400 });
        }

        if (!process.env.SUPABASE_SERVICE_ROLE_KEY) {
            console.error("[PaymentAPI] CRITICAL: SUPABASE_SERVICE_ROLE_KEY is missing from environment variables");
            return NextResponse.json({
                error: "Server configuration incomplete: Missing Supabase Service Role Key. Please add it to your hosting dashboard."
            }, { status: 500 });
        }

        const supabase = createAdminClient();

        // 1. Fetch Order Items (using Admin client to skip RLS)
        const { data: orderItems, error: itemsError } = await supabase
            .from('order_items')
            .select('product_id, quantity, price_at_purchase')
            .eq('order_id', order_id);

        if (itemsError) {
            console.error("[PaymentAPI] Items Fetch Error:", itemsError);
            return NextResponse.json({ error: "Failed to verify order items" }, { status: 500 });
        }

        if (!orderItems || orderItems.length === 0) {
            console.warn(`[PaymentAPI] No items found for order: ${order_id}`);
            return NextResponse.json({ error: "Order items not found" }, { status: 404 });
        }

        // 2. Calculate Total (Trusting price_at_purchase captured by the atomic RPC)
        let serverTotal = 0;
        for (const item of orderItems) {
            serverTotal += Number(item.price_at_purchase) * item.quantity;
        }

        if (serverTotal <= 0) {
            console.error(`[PaymentAPI] Invalid total calculated: ${serverTotal}`);
            return NextResponse.json({ error: "Invalid order total" }, { status: 400 });
        }

        const key_id = process.env.NEXT_PUBLIC_RAZORPAY_KEY_ID;
        const key_secret = process.env.RAZORPAY_KEY_SECRET;

        if (!key_id || !key_secret) {
            console.error("[PaymentAPI] Razorpay credentials missing from server environment");
            return NextResponse.json({ error: "Razorpay credentials missing" }, { status: 500 });
        }

        const instance = new Razorpay({
            key_id: key_id,
            key_secret: key_secret,
        });

        const options = {
            amount: Math.round(serverTotal * 100), // convert to paise
            currency: "INR",
            receipt: order_id,
        };

        const rzpOrder = await instance.orders.create(options);
        console.log(`[PaymentAPI] Razorpay Order Created: ${rzpOrder.id}`);

        return NextResponse.json(rzpOrder);
    } catch (error: any) {
        console.error("[PaymentAPI] Critical Failure:", error);
        return NextResponse.json({ error: error.message }, { status: 500 });
    }
}

import { NextRequest, NextResponse } from "next/server";
import Razorpay from "razorpay";
import crypto from "crypto";
import { createClient } from "@supabase/supabase-js";

// Helper to get Supabase client (Admin or User fallback)
import { createClient as createServerClient } from "@/lib/supabase-server";

export async function POST(req: NextRequest) {
    try {
        const body = await req.json();
        const { razorpay_order_id, razorpay_payment_id, razorpay_signature, order_id } = body;

        let supabase;
        const hasServiceKey = !!process.env.SUPABASE_SERVICE_ROLE_KEY;

        if (hasServiceKey) {
            // Use Service Role (Bypasses RLS)
            supabase = createClient(
                process.env.NEXT_PUBLIC_SUPABASE_URL!,
                process.env.SUPABASE_SERVICE_ROLE_KEY!
            );
        } else {
            console.warn("SUPABASE_SERVICE_ROLE_KEY missing. Falling back to User Context for verification.");
            // Use User Context (Cookies) - Requires RLS policy "Users can update own orders"
            supabase = await createServerClient();
        }

        if (!razorpay_order_id || !razorpay_payment_id || !razorpay_signature || !order_id) {
            return NextResponse.json({ error: "Missing required fields" }, { status: 400 });
        }

        // 1. Verify Signature
        const secret = process.env.RAZORPAY_KEY_SECRET;
        if (!secret) {
            console.error("RAZORPAY_KEY_SECRET is not set");
            return NextResponse.json({ error: "Server configuration error" }, { status: 500 });
        }

        const generated_signature = crypto
            .createHmac("sha256", secret)
            .update(razorpay_order_id + "|" + razorpay_payment_id)
            .digest("hex");

        if (generated_signature !== razorpay_signature) {
            return NextResponse.json({ error: "Invalid signature" }, { status: 400 });
        }

        // 2. Signature Valid - Update Order in DB
        const { error } = await supabase
            .from('orders')
            .update({
                payment_id: razorpay_payment_id,
                payment_status: 'paid',
                status: 'processing', // Move to processing once paid
                updated_at: new Date().toISOString()
            })
            .eq('id', order_id);

        if (error) {
            console.error("Failed to update order:", error);
            return NextResponse.json({ error: "Failed to update order status: " + error.message }, { status: 500 });
        }

        // 3. Send Confirmation Email (Server-Side)
        try {
            // Fetch full order details with items for email
            const { data: fullOrder } = await supabase
                .from('orders')
                .select('*, items:order_items(*)')
                .eq('id', order_id)
                .single();

            if (fullOrder) {
                const { sendOrderConfirmation } = await import("@/app/actions/email");
                await sendOrderConfirmation(fullOrder);
            }
        } catch (emailErr) {
            console.error("Failed to send email from verify route:", emailErr);
            // Non-blocking, return success for the payment
        }

        return NextResponse.json({ success: true, message: "Payment verified and order updated" });

    } catch (error: any) {
        console.error("Payment verification failed:", error);
        return NextResponse.json({ error: error.message || "Internal Server Error" }, { status: 500 });
    }
}

import { NextRequest, NextResponse } from "next/server";
import crypto from "crypto";
import { createClient } from "@supabase/supabase-js";

// Initialize Supabase Admin Client
export async function POST(req: NextRequest) {
    // Initialize Supabase Admin Client inside handler
    const supabaseAdmin = createClient(
        process.env.NEXT_PUBLIC_SUPABASE_URL!,
        process.env.SUPABASE_SERVICE_ROLE_KEY!
    );

    try {
        const body = await req.text(); // Get raw body for signature verification
        const signature = req.headers.get("x-razorpay-signature");

        if (!signature) {
            return NextResponse.json({ error: "Missing signature" }, { status: 400 });
        }

        const secret = process.env.RAZORPAY_WEBHOOK_SECRET;
        if (!secret) {
            console.error("RAZORPAY_WEBHOOK_SECRET is not set");
            return NextResponse.json({ error: "Server configuration error" }, { status: 500 });
        }

        // 1. Verify Webhook Signature
        const expectedSignature = crypto
            .createHmac("sha256", secret)
            .update(body)
            .digest("hex");

        if (expectedSignature !== signature) {
            return NextResponse.json({ error: "Invalid signature" }, { status: 400 });
        }

        // 2. Parse Event
        const event = JSON.parse(body);

        if (event.event === "payment.captured") {
            const payment = event.payload.payment.entity;
            const order_id = payment.notes?.order_id; // Assuming we pass order_id in notes when creating order

            if (order_id) {
                // Idempotent update
                await supabaseAdmin
                    .from('orders')
                    .update({
                        payment_id: payment.id,
                        payment_status: 'paid',
                        status: 'processing',
                        updated_at: new Date().toISOString()
                    })
                    .eq('id', order_id);

                console.log(`Webhook: Order ${order_id} marked as paid via webhook.`);
            } else {
                console.warn("Webhook: Payment captured but no order_id in notes.");
            }
        }

        return NextResponse.json({ status: "ok" });

    } catch (error: any) {
        console.error("Webhook processing failed:", error);
        return NextResponse.json({ error: error.message }, { status: 500 });
    }
}

