                        </div>

                        {/* Marketplace Links */}
                        <div className="mt-8 pt-6 border-t border-zinc-200 dark:border-white/10 space-y-4">
                            <h3 className="text-[10px] font-bold uppercase tracking-widest text-zinc-500 flex items-center gap-2">
