"use client";

import { motion } from "framer-motion";

interface AlchemicalProgressBarProps {
    currentStep: number;
    totalSteps: number;
}

export function AlchemicalProgressBar({ currentStep, totalSteps }: AlchemicalProgressBarProps) {
    const progress = (currentStep / totalSteps) * 100;

    return (
        <div className="relative w-full h-24 flex items-center justify-center p-4">
            {/* The Glass Vessel */}
            <div className="relative w-full max-w-2xl h-8 bg-zinc-900/50 rounded-full border border-white/10 overflow-hidden backdrop-blur-md">
                {/* Fluid Essence */}
                <motion.div
                    className="absolute inset-0 bg-blue-500/30"
                    initial={{ x: "-100%" }}
                    animate={{ x: `${progress - 100}%` }}
                    transition={{ type: "spring", damping: 20, stiffness: 50 }}
                >
                    {/* Animated Bubbles */}
                    {[...Array(10)].map((_, i) => (
                        <motion.div
                            key={i}
                            className="absolute w-2 h-2 bg-blue-400 rounded-full blur-[1px]"
                            animate={{
                                y: [0, -20, 0],
                                x: [0, (Math.random() - 0.5) * 50, 0],
                                opacity: [0, 0.8, 0]
                            }}
                            transition={{
                                duration: 2 + Math.random() * 2,
                                repeat: Infinity,
                                delay: Math.random() * 2
                            }}
                            style={{ left: `${Math.random() * 100}%`, bottom: "10%" }}
                        />
                    ))}

                    {/* Glowing Surface */}
                    <div className="absolute top-0 right-0 h-full w-2 bg-blue-400 blur-[4px] shadow-[0_0_15px_rgba(96,165,250,0.8)]" />
                </motion.div>

                {/* Glass Highlights */}
                <div className="absolute inset-0 bg-gradient-to-b from-white/10 to-transparent pointer-events-none" />
            </div>

            {/* Step Indicators */}
            <div className="absolute inset-x-0 bottom-0 flex justify-between px-4">
                {[...Array(totalSteps)].map((_, i) => (
                    <div
                        key={i}
                        className={`text-[10px] font-black uppercase tracking-[0.2em] transition-colors duration-500 ${i < currentStep ? "text-blue-400" : "text-zinc-600"}`}
                    >
                        Step 0{i + 1}
                    </div>
                ))}
            </div>
        </div>
    );
}

"use client";

import React, { useEffect, useRef } from 'react';
import { useScroll } from 'framer-motion';
import { useSensory } from '@/components/providers/SensoryProvider';
import { useEnvironment } from '@/components/providers/EnvironmentalProvider';

interface Particle {
    x: number;
    y: number;
    z: number; // Depth property
    size: number;
    speedX: number;
    speedY: number;
    opacity: number;
    color: string;
}

export function AtmosphereParticles() {
    const { theme, performance } = useEnvironment();
    const canvasRef = useRef<HTMLCanvasElement>(null);
    const { scrollYProgress } = useScroll();
    const { playBirdChirp } = useSensory();
    const mouseRef = useRef({ x: 0, y: 0 });
    const particlesRef = useRef<Particle[]>([]);
    const velocityRef = useRef(0);
    const lastScrollY = useRef(0);

    useEffect(() => {
        if (performance?.particles_enabled === false) return;
        const canvas = canvasRef.current;
        if (!canvas) return;

        const ctx = canvas.getContext('2d');
        if (!ctx) return;

        const resize = () => {
            canvas.width = window.innerWidth;
            canvas.height = window.innerHeight;
            init();
        };

        const init = () => {
            const count = Math.min(Math.floor((window.innerWidth / 20) * theme.particleIntensity), 150);
            particlesRef.current = [];
            for (let i = 0; i < count; i++) {
                const z = Math.random() * 0.5 + 0.1; // Depth from 0.1 to 0.6
                particlesRef.current.push({
                    x: Math.random() * canvas.width,
                    y: Math.random() * canvas.height,
                    z,
                    size: (Math.random() * 2 + 1) * z * 2,
                    speedX: (Math.random() - 0.5) * 0.5 * theme.windVelocity * theme.animationIntensity * z,
                    speedY: (Math.random() - 0.5) * 0.5 * theme.windVelocity * theme.animationIntensity * z,
                    opacity: (Math.random() * 0.5 + 0.1) * z * 1.5,
                    color: i % 2 === 0 ? theme.accentColor : 'rgba(139, 92, 246, 0.4)'
                });
            }
        };

        const handleMouseMove = (e: MouseEvent) => {
            mouseRef.current = { x: e.clientX, y: e.clientY };
        };

        window.addEventListener('resize', resize);
        window.addEventListener('mousemove', handleMouseMove);
        resize();

        let animationFrame: number;

        const animate = () => {
            ctx.clearRect(0, 0, canvas.width, canvas.height);

            // Smoothly interpolate velocity
            const currentScrollY = window.scrollY;
            const targetVelocity = (currentScrollY - lastScrollY.current) * 0.15;

            velocityRef.current += (targetVelocity - velocityRef.current) * 0.1;
            lastScrollY.current = currentScrollY;

            particlesRef.current.forEach(p => {
                // Drift with velocity (affected by depth)
                p.y -= velocityRef.current * p.z;

                // Base movement + organic jitter + depth scaling
                p.x += p.speedX + (Math.sin(Date.now() * 0.001 + p.y) * 0.1 * p.z);
                p.y += p.speedY;

                // Mouse repulsion (organic field - affected by depth)
                const dx = mouseRef.current.x - p.x;
                const dy = mouseRef.current.y - p.y;
                const distance = Math.sqrt(dx * dx + dy * dy);
                if (distance < 200 * p.z) {
                    const force = (200 * p.z - distance) / (200 * p.z);
                    p.x -= dx * force * 0.03 * p.z;
                    p.y -= dy * force * 0.03 * p.z;
                }

                // Warp around screen
                if (p.x < -50) p.x = canvas.width + 50;
                if (p.x > canvas.width + 50) p.x = -50;
                if (p.y < -50) p.y = canvas.height + 50;
                if (p.y > canvas.height + 50) p.y = -50;

                // Draw
                ctx.beginPath();
                ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
                ctx.fillStyle = p.color;
                ctx.globalAlpha = p.opacity;
                ctx.fill();
            });

            animationFrame = requestAnimationFrame(animate);
        };

        animate();

        return () => {
            window.removeEventListener('resize', resize);
            window.removeEventListener('mousemove', handleMouseMove);
            cancelAnimationFrame(animationFrame);
        };
    }, [theme, performance?.particles_enabled]);

    if (performance?.particles_enabled === false) return null;

    return (
        <canvas
            ref={canvasRef}
            className="fixed inset-0 pointer-events-none z-[1] transition-opacity duration-1000"
            style={{
                opacity: theme.mode === 'midnight' ? 0.3 : 0.5,
                filter: 'blur(1px)'
            }}
        />
    );
}

"use client";

import { useRef, useState, useEffect } from "react";
import { usePathname } from "next/navigation";
import { motion, useMotionValue, useSpring, AnimatePresence } from "framer-motion";
import { useEnvironment } from "@/components/providers/EnvironmentalProvider";

interface TrailPoint {
    x: number;
    y: number;
    age: number;
    id: number;
}

export function CustomCursor() {
    const { performance } = useEnvironment();
    const pathname = usePathname();
    const canvasRef = useRef<HTMLCanvasElement>(null);
    const pointsRef = useRef<TrailPoint[]>([]);
    const requestRef = useRef<number>(0);

    const [cursorState, setCursorState] = useState<{
        type: 'default' | 'pointer' | 'text' | 'view' | 'drag';
        label?: string;
    }>({ type: 'default' });
    const [isMouseDown, setIsMouseDown] = useState(false);
    const [magneticTarget, setMagneticTarget] = useState<{ x: number, y: number } | null>(null);

    const mouseX = useMotionValue(0);
    const mouseY = useMotionValue(0);

    // Precise dot (very fast)
    const dotSpringConfig = { damping: 40, stiffness: 800 };
    const dotX = useSpring(mouseX, dotSpringConfig);
    const dotY = useSpring(mouseY, dotSpringConfig);

    // Lagging ring (slower, luxury feel)
    const ringSpringConfig = { damping: 30, stiffness: 300, mass: 0.5 };
    const ringX = useSpring(mouseX, ringSpringConfig);
    const ringY = useSpring(mouseY, ringSpringConfig);

    useEffect(() => {
        const isAdmin = pathname?.startsWith("/admin");
        if (isAdmin || performance?.custom_cursor_enabled === false) return;

        const canvas = canvasRef.current;
        if (!canvas) return;
        const ctx = canvas.getContext('2d');
        if (!ctx) return;

        const resize = () => {
            canvas.width = window.innerWidth;
            canvas.height = window.innerHeight;
        };
        window.addEventListener('resize', resize);
        resize();

        const animate = () => {
            ctx.clearRect(0, 0, canvas.width, canvas.height);

            // Update points
            pointsRef.current = pointsRef.current
                .map(p => ({ ...p, age: p.age + 1 }))
                .filter(p => p.age < 30);

            // Draw trail
            if (pointsRef.current.length > 2) {
                ctx.beginPath();
                ctx.moveTo(pointsRef.current[0].x, pointsRef.current[0].y);

                for (let i = 1; i < pointsRef.current.length; i++) {
                    const p = pointsRef.current[i];
                    const opacity = Math.max(0, (1 - p.age / 30) * 0.3);

                    // Alchemical blue ember tone
                    ctx.strokeStyle = `rgba(59, 130, 246, ${opacity})`;
                    ctx.shadowBlur = 10;
                    ctx.shadowColor = `rgba(59, 130, 246, ${opacity})`;
                    ctx.lineWidth = (1 - p.age / 30) * 8;
                    ctx.lineCap = 'round';
                    ctx.lineJoin = 'round';

                    ctx.lineTo(p.x, p.y);
                    ctx.stroke();
                    ctx.beginPath();
                    ctx.moveTo(p.x, p.y);
                }
            }

            requestRef.current = requestAnimationFrame(animate);
        };

        requestRef.current = requestAnimationFrame(animate);
        return () => {
            window.removeEventListener('resize', resize);
            cancelAnimationFrame(requestRef.current!);
        };
    }, [pathname, performance?.custom_cursor_enabled]);

    useEffect(() => {
        const moveCursor = (e: MouseEvent) => {
            const { clientX, clientY } = e;
            mouseX.set(clientX);
            mouseY.set(clientY);

            // Add point to trail
            pointsRef.current.push({
                x: clientX,
                y: clientY,
                age: 0,
                id: Date.now()
            });

            // Magnetic Logic - Check for nearby magnetic elements
            const target = e.target as HTMLElement;
            const magneticElement = target.closest('[data-magnetic]') as HTMLElement;

            if (magneticElement) {
                const rect = magneticElement.getBoundingClientRect();
                const centerX = rect.left + rect.width / 2;
                const centerY = rect.top + rect.height / 2;

                // Calculate distance from mouse to center
                const distance = Math.sqrt(Math.pow(clientX - centerX, 2) + Math.pow(clientY - centerY, 2));

                if (distance < 100) { // Attraction radius
                    setMagneticTarget({ x: centerX, y: centerY });
                    return;
                }
            }
            setMagneticTarget(null);
        };

        const handleMouseDown = () => setIsMouseDown(true);
        const handleMouseUp = () => setIsMouseDown(false);

        const handleHoverStart = (e: MouseEvent) => {
            const target = e.target as HTMLElement;
            const interactive = target.closest('a, button, input, textarea, .cursor-pointer, [data-cursor]');

            if (interactive) {
                const cursorType = (interactive as HTMLElement).getAttribute('data-cursor') as any || 'pointer';
                const label = (interactive as HTMLElement).getAttribute('data-cursor-label');
                setCursorState({ type: cursorType, label: label || undefined });
            }
        };
        const handleHoverEnd = () => setCursorState({ type: 'default' });

        window.addEventListener("mousemove", moveCursor);
        window.addEventListener("mousedown", handleMouseDown);
        window.addEventListener("mouseup", handleMouseUp);
        window.addEventListener("mouseover", handleHoverStart);
        window.addEventListener("mouseout", handleHoverEnd);

        return () => {
            window.removeEventListener("mousemove", moveCursor);
            window.removeEventListener("mousedown", handleMouseDown);
            window.removeEventListener("mouseup", handleMouseUp);
            window.removeEventListener("mouseover", handleHoverStart);
            window.removeEventListener("mouseout", handleHoverEnd);
        };
    }, [pathname, performance?.custom_cursor_enabled]);

    const isAdmin = pathname?.startsWith("/admin");
    const isCustomCursorActive = !isAdmin && performance?.custom_cursor_enabled !== false;

    // Dynamic cursor-none management
    useEffect(() => {
        if (isCustomCursorActive) {
            document.body.classList.add('cursor-none');
        } else {
            document.body.classList.remove('cursor-none');
        }

        return () => {
            document.body.classList.remove('cursor-none');
        };
    }, [isCustomCursorActive]);

    if (!isCustomCursorActive) return null;


    const isHovering = cursorState.type !== 'default';

    return (
        <div className="fixed inset-0 pointer-events-none z-[9999]">
            {/* Ether Trail Canvas */}
            <canvas
                ref={canvasRef}
                className="fixed inset-0 pointer-events-none z-[-1]"
            />

            {/* Lagging Outer Ring */}
            <motion.div
                className="fixed top-0 left-0 w-10 h-10 border border-white mix-blend-difference rounded-full flex items-center justify-center overflow-hidden"
                style={{
                    x: magneticTarget ? dotX : ringX,
                    y: magneticTarget ? dotY : ringY,
                    translateX: "-50%",
                    translateY: "-50%",
                }}
                animate={{
                    scale: isMouseDown ? 0.8 : (isHovering ? (cursorState.type === 'view' ? 3.5 : 2.2) : 1),
                    backgroundColor: cursorState.type === 'view'
                        ? "rgba(255,255,255,1)"
                        : (isHovering ? "rgba(255,255,255,0.1)" : "rgba(255,255,255,0)"),
                    borderWidth: "1px",
                    borderColor: isHovering ? "rgba(255,255,255,0.2)" : "rgba(255,255,255,1)",
                }}
                transition={{ type: "spring", stiffness: 250, damping: 25 }}
            >
                <AnimatePresence>
                    {cursorState.label && (
                        <motion.span
                            initial={{ opacity: 0, scale: 0.5 }}
                            animate={{ opacity: 1, scale: 1 }}
                            exit={{ opacity: 0, scale: 0.5 }}
                            className="text-[8px] font-black uppercase tracking-tighter text-black mix-blend-normal"
                        >
                            {cursorState.label}
                        </motion.span>
                    )}
                </AnimatePresence>
            </motion.div>

            {/* Precision Center Dot */}
            <motion.div
                className="fixed top-0 left-0 w-1 h-1 bg-white mix-blend-difference rounded-full"
                style={{
                    x: dotX,
                    y: dotY,
                    translateX: "-50%",
                    translateY: "-50%",
                }}
                animate={{
                    scale: isHovering ? 0 : 1,
                    opacity: magneticTarget ? 0 : 1
                }}
            />
        </div>
    );
}

