"use client";

import { useEffect, useState } from "react";
import { motion, AnimatePresence } from "framer-motion";

export function Preloader() {
    const [isLoading, setIsLoading] = useState(true);
    const [count, setCount] = useState(0);

    useEffect(() => {
        // Check if we've already shown the loader this session
        const hasLoaded = sessionStorage.getItem("hasLoaded");
        if (hasLoaded) {
            setIsLoading(false);
            return;
        }

        // Lock scroll
        document.body.style.overflow = "hidden";

        // Counter Logic
        const interval = setInterval(() => {
            setCount(prev => {
                if (prev >= 100) {
                    clearInterval(interval);
                    return 100;
                }
                // Randomize increment for "realistic" load feel
                return prev + Math.floor(Math.random() * 10) + 1;
            });
        }, 100);

        // Completion Logic
        const timer = setTimeout(() => {
            setIsLoading(false);
            document.body.style.overflow = "auto";
            sessionStorage.setItem("hasLoaded", "true");
        }, 2500);

        return () => {
            document.body.style.overflow = "auto";
            clearTimeout(timer);
            clearInterval(interval);
        };
    }, []);

    return (
        <AnimatePresence mode="wait">
            {isLoading && (
                <motion.div
                    className="fixed inset-0 z-[99999] flex flex-col items-center justify-center bg-[#050505] text-white overflow-hidden origin-top"
                    exit={{
                        scaleY: 0,
                        transition: { duration: 1.2, ease: [0.76, 0, 0.24, 1], delay: 0.2 }
                    }}
                >
                    {/* Atmospheric Glow Layer */}
                    <div className="absolute inset-0 z-0">
                        <motion.div
                            animate={{
                                scale: [1, 1.2, 1],
                                opacity: [0.1, 0.2, 0.1],
                            }}
                            transition={{ duration: 10, repeat: Infinity }}
                            className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-full h-full bg-blue-500/10 blur-[200px] rounded-full"
                        />
                    </div>

                    <div className="relative z-10 flex flex-col items-center w-full px-6">
                        <div className="overflow-hidden mb-8 md:mb-12">
                            <motion.div
                                initial={{ y: "100%" }}
                                animate={{ y: 0 }}
                                transition={{ duration: 1.5, ease: [0.23, 1, 0.32, 1] }}
                            >
                                <h1 className="text-3xl sm:text-5xl md:text-8xl font-black tracking-[0.2em] md:tracking-[0.4em] uppercase mix-blend-difference font-heading text-gradient text-center">
                                    We Naturals
                                </h1>
                            </motion.div>
                        </div>

                        {/* Cinematic Laser Loading Bar */}
                        <div className="w-[80vw] max-w-sm h-[2px] bg-white/5 relative overflow-hidden rounded-full mb-4">
                            <motion.div
                                className="absolute inset-y-0 left-0 bg-gradient-to-r from-blue-600 to-blue-400"
                                initial={{ width: "0%" }}
                                animate={{ width: `${count}%` }}
                                transition={{ type: "spring", stiffness: 40, damping: 20 }}
                            />
                            <motion.div
                                className="absolute inset-y-0 left-0 bg-white/30 blur-md"
                                initial={{ width: "0%" }}
                                animate={{ width: `${count}%` }}
                                transition={{ type: "spring", stiffness: 40, damping: 20 }}
                            />
                        </div>

                        <div className="flex justify-between w-[80vw] max-w-sm">
                            <motion.p
                                initial={{ opacity: 0 }}
                                animate={{ opacity: 0.4 }}
                                className="text-[8px] md:text-[10px] uppercase font-bold tracking-[0.2em] md:tracking-[0.3em] font-mono"
                            >
                                Initializing Core
                            </motion.p>
                            <motion.p
                                initial={{ opacity: 0 }}
                                animate={{ opacity: 0.4 }}
                                className="text-[8px] md:text-[10px] uppercase font-bold tracking-[0.2em] md:tracking-[0.3em] font-mono"
                            >
                                {Math.min(count, 100)}%
                            </motion.p>
                        </div>
                    </div>

                    {/* Reveal Background (Pre-cache feel) */}
                    <div className="absolute bottom-10 left-1/2 -translate-x-1/2 pointer-events-none opacity-20">
                        <div className="text-[8px] font-mono uppercase tracking-widest text-zinc-500 animate-pulse">
                            Synthetic Biology meets Botanical Purity
                        </div>
                    </div>
                </motion.div>
            )}
        </AnimatePresence>
    );
}

import React, { useRef } from "react";
import { motion, useScroll, useTransform } from "framer-motion";
import { useEnvironment } from "@/components/providers/EnvironmentalProvider";

export function RecursiveGeometry() {
    const { theme, ascension, performance } = useEnvironment();
    const { scrollYProgress } = useScroll();

    const scale = useTransform(scrollYProgress, [0, 1], [0.8, 1.5]);
    const opacity = useTransform(scrollYProgress, [0, 0.5, 1], [0.1, 0.2, 0.1]);
    const rotate = useTransform(scrollYProgress, [0, 1], [0, 360]);

    if (performance?.recursive_geometry_enabled === false) return null;

    return (
        <motion.div
            className="absolute inset-0 z-0 pointer-events-none overflow-hidden flex items-center justify-center"
            style={{ opacity, scale, rotate }}
        >
            <svg viewBox="0 0 400 400" className="w-[150%] h-[150%] text-blue-500/20 dark:text-blue-400/10">
                <defs>
                    <radialGradient id="grad-recursive" cx="50%" cy="50%" r="50%">
                        <stop offset="0%" stopColor="currentColor" stopOpacity="0.8" />
                        <stop offset="100%" stopColor="currentColor" stopOpacity="0" />
                    </radialGradient>
                </defs>

                {/* Base Flower of Life Pattern */}
                {[...Array(3)].map((_, layer) => (
                    <motion.g
                        key={layer}
                        animate={{
                            rotate: layer % 2 === 0 ? 360 : -360,
                        }}
                        transition={{
                            duration: (20 + layer * 10) / ((ascension?.recursive_speed ?? 1) * theme.animationIntensity),
                            repeat: Infinity,
                            ease: "linear"
                        }}
                        style={{ originX: "200px", originY: "200px" }}
                    >
                        {[...Array(6)].map((_, i) => (
                            <circle
                                key={i}
                                cx={200 + (layer * 40 + 60) * Math.cos(i * 60 * Math.PI / 180)}
                                cy={200 + (layer * 40 + 60) * Math.sin(i * 60 * Math.PI / 180)}
                                r={100 - layer * 20}
                                fill="none"
                                stroke="currentColor"
                                strokeWidth="0.5"
                                strokeDasharray="2 2"
                            />
                        ))}
                    </motion.g>
                ))}

                {/* Recursive Fractal Elements */}
                <FractalCircles
                    cx={200}
                    cy={200}
                    r={100}
                    depth={0}
                    maxDepth={Math.min(ascension?.recursive_depth ?? 3, 5)}
                    scrollY={scrollYProgress}
                />
            </svg>
        </motion.div>
    );
}

function FractalCircles({ cx, cy, r, depth, maxDepth, scrollY }: { cx: number, cy: number, r: number, depth: number, maxDepth: number, scrollY: any }) {
    if (depth >= maxDepth) return null;

    return (
        <g>
            <circle cx={cx} cy={cy} r={r} fill="none" stroke="currentColor" strokeWidth="0.5" opacity={0.3} />
            {[...Array(6)].map((_, i) => {
                const angle = i * 60 * Math.PI / 180;
                const nextX = cx + r * Math.cos(angle);
                const nextY = cy + r * Math.sin(angle);
                return (
                    <FractalCircles
                        key={i}
                        cx={nextX}
                        cy={nextY}
                        r={r / 2}
                        depth={depth + 1}
                        maxDepth={maxDepth}
                        scrollY={scrollY}
                    />
                );
            })}
        </g>
    );
}

"use client";

import { motion, useInView, Variants } from "framer-motion";
import { useRef, ReactNode } from "react";

import { useEnvironment } from "@/components/providers/EnvironmentalProvider";

interface ScrollRevealProps {
    children: ReactNode;
    className?: string;
    delay?: number;
    direction?: "up" | "down" | "left" | "right" | "none";
    distance?: number;
    duration?: number;
}

export function ScrollReveal({
    children,
    className = "",
    delay = 0,
    direction = "up",
    distance = 40,
    duration = 0.8
}: ScrollRevealProps) {
    const { performance, theme } = useEnvironment();
    const isAnimationEnabled = !performance.eco_mode && theme.animationIntensity > 0;

    const ref = useRef(null);
    const isInView = useInView(ref, { once: true, amount: 0.2 });

    const getInitialProps = () => {
        switch (direction) {
            case "up": return { y: distance, opacity: 0 };
            case "down": return { y: -distance, opacity: 0 };
            case "left": return { x: distance, opacity: 0 };
            case "right": return { x: -distance, opacity: 0 };
            case "none": return { scale: 0.9, opacity: 0 };
            default: return { y: distance, opacity: 0 };
        }
    };

    return (
        <motion.div
            ref={ref}
            initial={isAnimationEnabled ? getInitialProps() : { x: 0, y: 0, opacity: 1, scale: 1 }}
            animate={(isInView || !isAnimationEnabled) ? { x: 0, y: 0, opacity: 1, scale: 1 } : getInitialProps()}
            transition={{
                duration: isAnimationEnabled ? (duration / Math.max(0.1, theme.animationIntensity)) : 0,
                delay: isAnimationEnabled ? delay : 0,
                ease: [0.23, 1, 0.32, 1] // Power4.easeOut
            }}
            className={className}
        >
            {children}
        </motion.div>
    );
}

"use client";

import { useEffect } from "react";
import { usePathname } from "next/navigation";
import Lenis from "lenis";
import { useEnvironment } from "@/components/providers/EnvironmentalProvider";

export function SmoothScroll() {
    const { performance } = useEnvironment();
    const pathname = usePathname();
    const isAdmin = pathname?.startsWith("/admin");

    useEffect(() => {
        if (isAdmin || performance?.smooth_scroll_enabled === false) return;

        const lenis = new Lenis({
            duration: 1.2,
            easing: (t) => Math.min(1, 1.001 - Math.pow(2, -10 * t)),
            orientation: 'vertical',
            gestureOrientation: 'vertical',
            smoothWheel: true,
            wheelMultiplier: 1,
            touchMultiplier: 2,
        });

        // Skew Effect Logic
        let velocity = 0;
        const skewTarget = document.querySelector('main') || document.body;

        lenis.on('scroll', (e: any) => {
            velocity = e.velocity;
        });

        function raf(time: number) {
            lenis.raf(time);

            // Apply skew based on velocity
            if (skewTarget) {
                const skew = Math.min(Math.max(velocity * 0.08, -2), 2); // Cap at 2deg
                const filter = Math.min(Math.abs(velocity * 0.01), 2); // Subtle blur

                // Using CSS variables for performance (handled in layout/globals)
                // Or direct style for immediate feedback
                (skewTarget as HTMLElement).style.transform = `skewY(${skew}deg)`;
                (skewTarget as HTMLElement).style.transition = 'transform 0.4s cubic-bezier(0.23, 1, 0.32, 1)';
            }

            requestAnimationFrame(raf);
        }

        requestAnimationFrame(raf);

        return () => {
            lenis.destroy();
            if (skewTarget) {
                (skewTarget as HTMLElement).style.transform = '';
            }
        };
    }, [isAdmin, performance?.smooth_scroll_enabled]);

    return null;
}

"use client";

import { motion, useInView, useAnimation, Variants } from "framer-motion";
import { useEffect, useRef } from "react";

type SplitTextProps = {
    text: string;
    className?: string;
    delay?: number;
    duration?: number;
};

export function SplitText({ text, className = "", delay = 0, duration = 0.05 }: SplitTextProps) {
    const controls = useAnimation();
    const ref = useRef(null);
    const isInView = useInView(ref, { once: true, amount: 0.5 });

    useEffect(() => {
        if (isInView) {
            controls.start("visible");
        }
    }, [isInView, controls]);

    const words = text.split(" ");

    const container: Variants = {
        hidden: { opacity: 0 },
        visible: (i: number = 1) => ({
            opacity: 1,
            transition: {
                staggerChildren: duration,
                delayChildren: delay,
            },
        }),
    };

    const child: Variants = {
        hidden: {
            y: "110%",
            rotate: 5,
        },
        visible: {
            y: 0,
            rotate: 0,
            transition: {
                duration: 0.8,
                ease: [0.23, 1, 0.32, 1], // Power4.easeOut
            },
        },
    };

    return (
        <motion.span
            ref={ref}
            variants={container}
            initial="hidden"
            animate={controls}
            className={`inline-flex flex-wrap ${className}`}
        >
            {words.map((word, i) => (
                <span key={i} className="inline-block mr-[0.25em] overflow-hidden py-[0.1em] -my-[0.1em]">
                    {word.split("").map((char, j) => (
                        <motion.span
                            key={j}
                            variants={child}
                            className="inline-block origin-bottom"
                        >
                            {char}
                        </motion.span>
                    ))}
                </span>
            ))}
        </motion.span>
    );
}

"use client";

import { create } from 'zustand';
import { persist, createJSONStorage } from 'zustand/middleware';

export interface CartItem {
    id: string;
    name: string;
    price: string | number;
    image: string;
    quantity: number;
}

interface CartStore {
    items: CartItem[];
    isOpen: boolean;
    flyItem: { x: number, y: number, image: string } | null;
    addItem: (product: any) => void;
    removeItem: (id: string) => void;
    updateQuantity: (id: string, quantity: number) => void;
    toggleCart: () => void;
    clearCart: () => void;
    triggerFly: (x: number, y: number, image: string) => void;
    clearFly: () => void;
}

export const useCart = create<CartStore>()(
    persist(
        (set, get) => ({

            items: [],
            isOpen: false,
            flyItem: null,
            triggerFly: (x, y, image) => {
                set({ flyItem: { x, y, image } });
            },
            clearFly: () => set({ flyItem: null }),
            addItem: (product) => {
                const items = get().items;
                const existingItem = items.find((item) => item.id === product.id);

                if (existingItem) {
                    set({
                        items: items.map((item) =>
                            item.id === product.id
                                ? { ...item, quantity: item.quantity + 1 }
                                : item
                        ),
                    });
                } else {
                    set({ items: [...items, { ...product, quantity: 1 }] });
                }
            },
            removeItem: (id) => {
                set({ items: get().items.filter((item) => item.id !== id) });
            },
            updateQuantity: (id, quantity) => {
                set({
                    items: get().items.map((item) =>
                        item.id === id ? { ...item, quantity: Math.max(0, quantity) } : item
                    ).filter(item => item.quantity > 0),
                });
            },
            toggleCart: () => set({ isOpen: !get().isOpen }),
            clearCart: () => set({ items: [] }),
        }),
        {
            name: 'cart-storage',
            storage: createJSONStorage(() => localStorage),
            partialize: (state) => ({ items: state.items } as any), // Only persist items
        }
    )
);

export const getCartTotal = (items: CartItem[]) => {
    return items.reduce((acc, item) => {
        const priceStr = String(item.price);
        const priceValue = parseFloat(priceStr.replace(/[^0-9.-]+/g, ""));
        return acc + (isNaN(priceValue) ? 0 : priceValue) * item.quantity;
    }, 0);
};

