export function useContent(
    key: 'content_homepage' | 'content_global' | 'content_philosophy' | 'content_featured' | 'content_journal' | 'content_testimonials' | 'content_pages' | 'content_categories' | 'youtube_shorts' | 'content_design_system' | 'content_navigation' | 'content_marketing' | 'homepage_layout' | 'content_system' | 'content_marquee_top' | 'content_marquee_bottom',
    initialData?: any
) {
    const [content, setContent] = useState<any>(initialData || DEFAULT_CONTENT[key]);

    useEffect(() => {
        // If we don't have initialData, fetch it from Supabase
        if (!initialData) {
            const fetchContent = async () => {
                const supabase = createClient();
                const { data } = await supabase.from('site_config').select('value').eq('key', key).single();
                if (data?.value) {
                    setContent(data.value);
                }
            };
            fetchContent();
        }

        // Listen for real-time preview updates from Admin Panel
        const handleMessage = (event: MessageEvent) => {
            if (event.data?.type === 'CMS_UPDATE_ALL') {
                if (event.data.data?.[key]) {
                    setContent(event.data.data[key]);
                }
            }
        };

        window.addEventListener('message', handleMessage);
        return () => window.removeEventListener('message', handleMessage);
    }, [key, initialData]);

    return content;
}

"use client";

import { useCallback, useRef } from 'react';
import { getProductDetails } from '@/app/shop/actions';

// Global cache (outside hook to persist across re-renders/unmounts)
const productCache = new Map<string, any>();
const pendingRequests = new Set<string>();

export function useProductPrefetch() {
    const prefetch = useCallback(async (slug: string) => {
        if (!slug || productCache.has(slug) || pendingRequests.has(slug)) return;

        pendingRequests.add(slug);

        try {
            // Fetch data securely via Server Action
            const data = await getProductDetails(slug);
            if (data) {
                productCache.set(slug, data);
            }
        } catch (error) {
            console.error(`Failed to prefetch product: ${slug}`, error);
        } finally {
            pendingRequests.delete(slug);
        }
    }, []);

    const getCached = useCallback((slug: string) => {
        return productCache.get(slug);
    }, []);

    return { prefetch, getCached };
}

import { create } from 'zustand';
import { createClient } from '@/lib/supabase';

interface ThemeEditorState {
    cmsData: any;
    isSaving: boolean;
    isLoading: boolean;
    activeTab: string;
    snapshots: any[];
    isSnapshotLoading: boolean;

    // Actions
    setCmsData: (data: any) => void;
    setActiveTab: (tab: string) => void;
    updateSection: (sectionKey: string, data: any) => void;
    updateField: (sectionKey: string, fieldKey: string, value: any) => void;
    deepUpdateField: (sectionKey: string, subSectionKey: string, fieldKey: string, value: any) => void;
    moveSection: (index: number, direction: 'up' | 'down') => void;
    toggleSectionVisibility: (sectionKey: string) => void;
    addNavItem: (type: 'header' | 'footer') => void;
    updateNavItem: (type: 'header' | 'footer', index: number, field: string, value: any) => void;
    removeNavItem: (type: 'header' | 'footer', index: number) => void;
    addFaqItem: () => void;
    updateFaqItem: (index: number, field: string, value: any) => void;
    removeFaqItem: (index: number) => void;
    addBlock: (page: string, type: string) => void;
    updateBlock: (page: string, blockId: string, field: string, value: any) => void;
    moveBlock: (page: string, index: number, direction: 'up' | 'down') => void;
    removeBlock: (page: string, blockId: string) => void;
    loadData: () => Promise<void>;
    saveData: () => Promise<{ success: boolean; error?: string }>;
    loadSnapshots: () => Promise<void>;
    saveSnapshot: (name: string) => Promise<{ success: boolean; error?: string }>;
    restoreSnapshot: (snapshot: any) => Promise<void>;
    deleteSnapshot: (id: string) => Promise<void>;
}

export const useThemeEditorStore = create<ThemeEditorState>((set, get) => ({
    cmsData: null,
    isSaving: false,
    isLoading: false,
    activeTab: 'design',
    snapshots: [],
    isSnapshotLoading: false,

    setCmsData: (cmsData) => set({ cmsData }),
    setActiveTab: (activeTab) => set({ activeTab }),

    updateSection: (sectionKey, data) => set((state) => ({
        cmsData: {
            ...state.cmsData,
            [sectionKey]: data
        }
    })),

    updateField: (sectionKey, fieldKey, value) => set((state) => ({
        cmsData: {
            ...state.cmsData,
            [sectionKey]: {
                ...(state.cmsData?.[sectionKey] || {}),
                [fieldKey]: value
            }
        }
    })),

    deepUpdateField: (sectionKey, subSectionKey, fieldKey, value) => set((state) => ({
        cmsData: {
            ...state.cmsData,
            [sectionKey]: {
                ...(state.cmsData?.[sectionKey] || {}),
                [subSectionKey]: {
                    ...(state.cmsData?.[sectionKey]?.[subSectionKey] || {}),
                    [fieldKey]: value
                }
            }
        }
    })),

    moveSection: (index, direction) => set((state) => {
        const newLayout = [...(state.cmsData?.homepage_layout || [])];
        if (direction === 'up' && index > 0) {
            [newLayout[index], newLayout[index - 1]] = [newLayout[index - 1], newLayout[index]];
        } else if (direction === 'down' && index < newLayout.length - 1) {
            [newLayout[index], newLayout[index + 1]] = [newLayout[index + 1], newLayout[index]];
        }
        return {
            cmsData: {
                ...state.cmsData,
                homepage_layout: newLayout
            }
        };
    }),

    toggleSectionVisibility: (sectionKey) => set((state) => {
        const prev = state.cmsData;
        if (!prev) return state;

        const newData = { ...prev };

        if (sectionKey === 'hero') {
            newData.content_homepage = {
                ...prev.content_homepage,
                hero: { ...prev.content_homepage?.hero, visible: prev.content_homepage?.hero?.visible === false ? true : false }
            };
        } else {
            const contentKeyMapping: Record<string, string> = {
                philosophy: 'content_philosophy',
                rituals: 'content_testimonials',
                shorts: 'youtube_shorts',
                featured: 'content_featured',
                journal: 'content_journal',
                categories: 'content_categories',
                marquee_top: 'content_marquee_top',
                marquee_bottom: 'content_marquee_bottom'
            };

            const contentKey = contentKeyMapping[sectionKey];
            if (contentKey) {
                newData[contentKey] = {
                    ...prev[contentKey],
                    visible: prev[contentKey]?.visible === false ? true : false
                };
            }
        }

        return { cmsData: newData };
    }),

    addNavItem: (type) => set((state) => {
        const prev = state.cmsData;
        if (!prev) return state;

        const newNav = { ...(prev.content_navigation || {}) };
        const list = [...(newNav[type] || [])];
        list.push({ label: 'New Link', href: '/', visible: true });
        newNav[type] = list;

        return { cmsData: { ...prev, content_navigation: newNav } };
    }),

    updateNavItem: (type, index, field, value) => set((state) => {
        const prev = state.cmsData;
        if (!prev) return state;

        const newNav = { ...(prev.content_navigation || {}) };
        const list = [...(newNav[type] || [])];
        if (list[index]) {
            list[index] = { ...list[index], [field]: value };
        }
        newNav[type] = list;

        return { cmsData: { ...prev, content_navigation: newNav } };
    }),

    removeNavItem: (type, index) => set((state) => {
        const prev = state.cmsData;
        if (!prev) return state;

        const newNav = { ...(prev.content_navigation || {}) };
        const list = [...(newNav[type] || [])];
        list.splice(index, 1);
        newNav[type] = list;

        return { cmsData: { ...prev, content_navigation: newNav } };
    }),

    addFaqItem: () => set((state) => {
        const prev = state.cmsData;
        if (!prev) return state;

        const newPages = { ...(prev.content_pages || {}) };
        const faq = { ...(newPages.faq || {}) };
        const items = [...(faq.items || [])];
        items.push({ question: 'New Question', answer: '', visible: true });
        faq.items = items;
        newPages.faq = faq;

        return { cmsData: { ...prev, content_pages: newPages } };
    }),

    updateFaqItem: (index, field, value) => set((state) => {
        const prev = state.cmsData;
        if (!prev) return state;

        const newPages = { ...(prev.content_pages || {}) };
        const faq = { ...(newPages.faq || {}) };
        const items = [...(faq.items || [])];
        if (items[index]) {
            items[index] = { ...items[index], [field]: value };
        }
        faq.items = items;
        newPages.faq = faq;

        return { cmsData: { ...prev, content_pages: newPages } };
    }),

    removeFaqItem: (index) => set((state) => {
        const prev = state.cmsData;
        if (!prev) return state;

        const newPages = { ...(prev.content_pages || {}) };
        const faq = { ...(newPages.faq || {}) };
        const items = [...(faq.items || [])];
        items.splice(index, 1);
        faq.items = items;
        newPages.faq = faq;

        return { cmsData: { ...prev, content_pages: newPages } };
    }),

    addBlock: (page, type) => set((state) => {
        const prev = state.cmsData;
        if (!prev) return state;

        const newPages = { ...(prev.content_pages || {}) };
        const pageData = { ...(newPages[page] || {}) };
        const blocks = [...(pageData.blocks || [])];

        const newBlock = {
            id: crypto.randomUUID(),
            type,
            content: type === 'rich_text' ? { html: '' } : type === 'hero' ? { heading: '', subheading: '', image: '' } : { heading: '', text: '', image: '' }
        };

        blocks.push(newBlock);
        pageData.blocks = blocks;
        newPages[page] = pageData;

        return { cmsData: { ...prev, content_pages: newPages } };
    }),

    updateBlock: (page, blockId, field, value) => set((state) => {
        const prev = state.cmsData;
        if (!prev) return state;

        const newPages = { ...(prev.content_pages || {}) };
        const pageData = { ...(newPages[page] || {}) };
        const blocks = [...(pageData.blocks || [])].map(b => {
            if (b.id === blockId) {
                return { ...b, content: { ...b.content, [field]: value } };
            }
            return b;
        });

        pageData.blocks = blocks;
        newPages[page] = pageData;

        return { cmsData: { ...prev, content_pages: newPages } };
    }),

    moveBlock: (page, index, direction) => set((state) => {
        const prev = state.cmsData;
        if (!prev) return state;

        const newPages = { ...(prev.content_pages || {}) };
        const pageData = { ...(newPages[page] || {}) };
        const blocks = [...(pageData.blocks || [])];

        if (direction === 'up' && index > 0) {
            [blocks[index], blocks[index - 1]] = [blocks[index - 1], blocks[index]];
        } else if (direction === 'down' && index < blocks.length - 1) {
            [blocks[index], blocks[index + 1]] = [blocks[index + 1], blocks[index]];
        }

        pageData.blocks = blocks;
        newPages[page] = pageData;

        return { cmsData: { ...prev, content_pages: newPages } };
    }),

    removeBlock: (page, blockId) => set((state) => {
        const prev = state.cmsData;
        if (!prev) return state;

        const newPages = { ...(prev.content_pages || {}) };
        const pageData = { ...(newPages[page] || {}) };
        const blocks = [...(pageData.blocks || [])].filter(b => b.id !== blockId);

        pageData.blocks = blocks;
        newPages[page] = pageData;

        return { cmsData: { ...prev, content_pages: newPages } };
    }),

    loadData: async () => {
        set({ isLoading: true });
        const supabase = createClient();
        const keys = [
            'content_homepage',
            'content_global',
            'content_philosophy',
            'content_featured',
            'content_journal',
            'content_testimonials',
            'content_pages',
            'youtube_shorts',
            'content_categories',
            'content_design_system',
            'content_navigation',
            'content_marketing',
            'homepage_layout',
            'content_system',
            'content_ascension',
            'content_layout_spacing',
            'content_performance',
            'content_marquee_top',
            'content_marquee_bottom'
        ];

        const { data, error } = await supabase
            .from('site_config')
            .select('key, value')
            .in('key', keys);

        if (!error && data) {
            const newData: any = {};
            data.forEach((item: any) => {
                let val = item.value;
                if (!val) return;

                // Migration logic from ThemePage.tsx
                if (item.key === 'youtube_shorts' && Array.isArray(val)) {
                    val = { items: val, visible: true, header_visible: true, marquee_visible: true };
                }
                if (item.key === 'content_testimonials' && Array.isArray(val)) {
                    val = { items: val, visible: true, header_visible: true };
                }
                newData[item.key] = val;
            });
            set({ cmsData: newData });
        }
        set({ isLoading: false });
    },

    saveData: async () => {
        const { cmsData } = get();
        if (!cmsData) return { success: false, error: 'No data to save' };

        set({ isSaving: true });
        const supabase = createClient();

        const updates = Object.entries(cmsData).map(([key, value]) => ({
            key,
            value
        })).filter(u => u.value !== undefined);

        const { error } = await supabase
            .from('site_config')
            .upsert(updates);

        set({ isSaving: false });

        if (error) {
            console.error('Error saving theme:', error);
            return { success: false, error: error.message };
        }

        return { success: true };
    },

    loadSnapshots: async () => {
        set({ isSnapshotLoading: true });
        const supabase = createClient();

        try {
            const { data, error } = await supabase
                .from('site_snapshots')
                .select('*')
                .order('created_at', { ascending: false })
                .limit(20);

            if (error) throw error;
            set({ snapshots: data || [] });
        } catch (error) {
            console.error('Error loading snapshots:', error);
        } finally {
            set({ isSnapshotLoading: false });
        }
    },

    saveSnapshot: async (name: string) => {
        const { cmsData } = get();
        if (!cmsData) return { success: false, error: 'No data to snapshot' };

        set({ isSnapshotLoading: true });
        const supabase = createClient();

        try {
            const { error } = await supabase
                .from('site_snapshots')
                .insert({
                    snapshot_name: name,
                    data: cmsData
                });

            if (error) throw error;

            // Reload snapshots list
            await get().loadSnapshots();
            return { success: true };
        } catch (error: any) {
            console.error('Error saving snapshot:', error);
            return { success: false, error: error.message };
        } finally {
            set({ isSnapshotLoading: false });
        }
    },

    restoreSnapshot: async (snapshot: any) => {
        if (!snapshot.data) return;

        // 1. Update local state
        set({ cmsData: snapshot.data, isLoading: true });

        // 2. Persist to live site_config immediately
        // We reuse the saveData logic but with the new data
        const supabase = createClient();
        const updates = Object.entries(snapshot.data).map(([key, value]) => ({
            key,
            value
        })).filter(u => u.value !== undefined);

        try {
            const { error } = await supabase
                .from('site_config')
                .upsert(updates);

            if (error) throw error;
        } catch (error) {
            console.error('Error restoring snapshot to live site:', error);
            // Optionally revert local state or show error
        } finally {
            set({ isLoading: false });
        }
    },

    deleteSnapshot: async (id: string) => {
        set({ isSnapshotLoading: true });
        const supabase = createClient();

        try {
            const { error } = await supabase
                .from('site_snapshots')
                .delete()
                .eq('id', id);

            if (error) throw error;

            // Optimistic update
            set(state => ({
                snapshots: state.snapshots.filter(s => s.id !== id)
            }));
        } catch (error) {
            console.error('Error deleting snapshot:', error);
        } finally {
            set({ isSnapshotLoading: false });
        }
    }
}));

// Dynamically import jsPDF to avoid SSR/Node build issues
export const generateInvoicePDF = async (order: any) => {
    const { default: jsPDF } = await import("jspdf");
    const doc = new jsPDF();
    const pageWidth = doc.internal.pageSize.getWidth();
    const pageHeight = doc.internal.pageSize.getHeight();
    const margin = 20;
    let yPos = 20;

    // Define colors
    const primaryColor = [40, 40, 40]; // Dark Grey
    const secondaryColor = [100, 100, 100]; // Light Grey

    // Helper to load images
    const loadImage = (url: string) => {
        return new Promise<HTMLImageElement>((resolve, reject) => {
            const img = new Image();
            img.crossOrigin = "Anonymous";
            img.src = url;
            img.onload = () => resolve(img);
            img.onerror = () => reject(new Error(`Failed to load image: ${url}`));
        });
    };

    // --- IMAGES (Logo & Watermark) ---
    try {
        // 1. Watermark (Background)
        try {
            const watermarkUrl = "https://res.cloudinary.com/dbfltasjo/image/upload/v1770840963/Untitled_design_3_iy0pih.png";
            const watermarkImg = await loadImage(watermarkUrl);

            // Save state to handle transparency/opacity
            doc.saveGraphicsState();
            doc.setGState(new (doc as any).GState({ opacity: 0.1 })); // 10% opacity for watermark           const wmWidth = 150;
            const wmWidth = 150;
            const wmHeight = 150;
            const wmX = (pageWidth - wmWidth) / 2;
            const wmY = (pageHeight - wmHeight) / 2;

            doc.addImage(watermarkImg, 'PNG', wmX, wmY, wmWidth, wmHeight);
            doc.restoreGraphicsState();
        } catch (e) {
            console.warn("Watermark failed to load", e);
        }

        // 2. Logo
        const logoUrl = "https://res.cloudinary.com/dbfltasjo/image/upload/v1770733974/We_natural_250_x_100_px_nreaal.png";
        const logoImg = await loadImage(logoUrl);
        // Add logo (x, y, w, h)
        doc.addImage(logoImg, "PNG", margin, yPos - 10, 50, 20);

    } catch (e) {
        console.warn("Logo failed to load", e);
        // Fallback text
        doc.setFont("helvetica", "bold");
        doc.setFontSize(22);
        doc.setTextColor(primaryColor[0], primaryColor[1], primaryColor[2]);
        doc.text("We Naturals", margin, yPos + 10);
    }

    // --- HEADER INFO ---
    doc.setFont("helvetica", "bold");
    doc.setFontSize(16);
    doc.setTextColor(primaryColor[0], primaryColor[1], primaryColor[2]);
    doc.text("INVOICE", pageWidth - margin, yPos, { align: "right" });

    doc.setFont("helvetica", "normal");
    doc.setFontSize(10);
    doc.setTextColor(secondaryColor[0], secondaryColor[1], secondaryColor[2]);
    doc.text(`#${order.id.slice(0, 8).toUpperCase()}`, pageWidth - margin, yPos + 6, { align: "right" });
    doc.text(`Date: ${new Date(order.created_at).toLocaleDateString()}`, pageWidth - margin, yPos + 12, { align: "right" });

    yPos += 30;

    // --- DIVIDER ---
    doc.setLineWidth(0.5);
    doc.setDrawColor(200, 200, 200);
    doc.line(margin, yPos, pageWidth - margin, yPos);
    yPos += 15;

    // --- BILLING DETAILS ---
    doc.setFontSize(10);
    doc.setFont("helvetica", "bold");
    doc.setTextColor(primaryColor[0], primaryColor[1], primaryColor[2]);
    doc.text("Bill To:", margin, yPos);

    doc.setFont("helvetica", "normal");
    doc.setTextColor(secondaryColor[0], secondaryColor[1], secondaryColor[2]);
    yPos += 6;
    doc.text(order.customer_name || "Valued Customer", margin, yPos);
    yPos += 5;

    if (order.shipping_address) {
        // Handle both object and array/string formats just in case
        const addr = order.shipping_address;
        if (typeof addr === 'object') {
            if (addr.street) {
                doc.text(addr.street, margin, yPos);
                yPos += 5;
            }
            if (addr.city || addr.state || addr.pincode) {
                doc.text(`${addr.city || ''}, ${addr.state || ''} ${addr.pincode || ''}`, margin, yPos);
                yPos += 5;
            }
            if (addr.phone) doc.text(`Phone: ${addr.phone}`, margin, yPos);
        }
    }

    yPos += 20;

    // --- ITEM TABLE HEADER ---
    const col1 = margin;
    const col2 = pageWidth - 60; // Price
    const col3 = pageWidth - 40; // Qty
    const col4 = pageWidth - margin; // Total

    // Background for header
    doc.setFillColor(245, 245, 245);
    doc.rect(margin, yPos - 5, pageWidth - (margin * 2), 10, 'F');

    doc.setFont("helvetica", "bold");
    doc.setTextColor(primaryColor[0], primaryColor[1], primaryColor[2]);
    doc.text("Item", col1 + 5, yPos + 1);
    doc.text("Price", col2, yPos + 1, { align: "right" });
    doc.text("Qty", col3, yPos + 1, { align: "center" });
    doc.text("Total", col4 - 5, yPos + 1, { align: "right" });

    yPos += 12;

    // --- ITEMS ---
    doc.setFont("helvetica", "normal");
    doc.setTextColor(secondaryColor[0], secondaryColor[1], secondaryColor[2]);

    order.items.forEach((item: any) => {
        const name = item.product?.name || item.product_name || item.name || "Artifact";
        const price = Number(item.price_at_purchase || item.price || 0);
        const quantity = Number(item.quantity || 1);
        const total = price * quantity;

        // Handle long item names
        const splitName = doc.splitTextToSize(name, 90); // Wrap at 90 units

        doc.text(splitName, col1 + 5, yPos);
        doc.text(price.toFixed(2), col2, yPos, { align: "right" });
        doc.text(String(quantity), col3, yPos, { align: "center" });
        doc.text(total.toFixed(2), col4 - 5, yPos, { align: "right" });

        yPos += (splitName.length * 6) + 4; // Dynamic spacing based on lines
    });

    yPos += 5;
    doc.line(margin, yPos, pageWidth - margin, yPos);
    yPos += 10;

    // --- TOTALS ---
    const totalX = pageWidth - margin - 5;
    const labelX = pageWidth - margin - 50;

    doc.text("Subtotal:", labelX, yPos, { align: "right" });
    doc.text(Number(order.total_amount).toFixed(2), totalX, yPos, { align: "right" });
    yPos += 6;

    doc.text("Shipping:", labelX, yPos, { align: "right" });
    doc.text("0.00", totalX, yPos, { align: "right" });
    yPos += 8;

    doc.setFont("helvetica", "bold");
    doc.setFontSize(12);
    doc.setTextColor(primaryColor[0], primaryColor[1], primaryColor[2]);
    doc.text("Total Essence:", labelX, yPos, { align: "right" });
    doc.text(`Rs. ${Number(order.total_amount).toFixed(2)}`, totalX, yPos, { align: "right" });

    // --- FOOTER ---
    yPos += 30;
    doc.setFontSize(9);
    doc.setFont("helvetica", "italic");
    doc.setTextColor(150, 150, 150);
    doc.text("Thank you for choosing We Naturals.", pageWidth / 2, yPos, { align: "center" });
    doc.text("This is a computer-generated invoice.", pageWidth / 2, yPos + 5, { align: "center" });

    // Save
    doc.save(`WeNaturals_Invoice_${order.id.slice(0, 8)}.pdf`);
};

import { createClient } from "@/lib/supabase";
import { OrderPayloadSchema, OrderPayload } from "@/lib/schemas/order";

export interface OrderData extends OrderPayload { }

export const OrderService = {
    async createOrder(data: OrderData) {
        // 1. Zod Validation Gate
        const validatedData = OrderPayloadSchema.parse(data);
        const supabase = createClient();

        // 2. Prepare items for RPC (mapping to database types)
        const orderItems = validatedData.items.map(item => {
            const priceStr = String(item.price || "0");
            const priceValue = parseFloat(priceStr.replace(/[^0-9.-]+/g, ""));

            return {
                product_id: item.id,
                product_name: item.name || "Unknown Product",
                quantity: item.quantity,
                price_at_purchase: isNaN(priceValue) ? 0 : priceValue
            };
        });

        // 3. Call Atomic RPC
        // This handles stock validation, stock decrement, order insertion, and item insertion in ONE transaction.
        const { data: order, error: rpcError } = await supabase.rpc('create_order_v1', {
            p_user_id: validatedData.user_id,
            p_customer_email: validatedData.customer_email,
            p_customer_name: validatedData.customer_name,
            p_customer_phone: validatedData.customer_phone,
            p_shipping_address: validatedData.shipping_address,
            p_payment_method: validatedData.payment_method,
            p_payment_status: validatedData.payment_status,
            p_payment_id: validatedData.payment_id || null,
            p_items: orderItems
        });

        if (rpcError) {
            console.error("Order RPC Error:", rpcError);
            throw new Error(rpcError.message || "Failed to process order transaction.");
        }

        // Return the created order object returned by the RPC
        return order;
    },

    async saveAddress(userId: string, addressData: any) {
        const supabase = createClient();

        // Basic check to see if this exact address exists to avoid duplicates? 
        // For MVP, just insert.
        const { error } = await supabase
            .from('addresses')
            .insert({
                user_id: userId,
                name: `${addressData.firstName} ${addressData.lastName}`,
                phone: addressData.phone,
                street: addressData.street,
                city: addressData.city,
                district: addressData.district,
                state: addressData.state,
                pincode: addressData.pincode,
                is_default: false // Logic to make default can be added later
            });

        if (error) throw error;
    },

    async getOrders() {
        // This is a client-side fetch wrapper, usually for Admin.
        // It relies on RLS to allow viewing all orders (if admin).
        const supabase = createClient();

        const { data, error } = await supabase
            .from('orders')
            .select(`
                *,
                items:order_items (
                    id,
                    product_id,
                    product_name,
                    quantity,
                    price_at_purchase
                )
            `)
            .order('created_at', { ascending: false });

        if (error) throw error;
        return data;
    },

    async updateOrderPayment(orderId: string, paymentId: string, status: 'paid' | 'failed' = 'paid') {
        const supabase = createClient();
        const { error } = await supabase
            .from('orders')
            .update({
                payment_id: paymentId,
                payment_status: status,
            })
            .eq('id', orderId);

        if (error) throw error;
    },

    async updateOrderStatus(orderId: string, status: string, note?: string) {
        const supabase = createClient();

        // The database trigger will automatically create an order_history record
        const { error } = await supabase
            .from('orders')
            .update({ status })
            .eq('id', orderId);

        if (error) throw error;
    }
};

import { createClient } from "@/lib/supabase-server";

export const fetchProductBySlug = async (slug: string) => {
    const supabase = await createClient();

    // Fetch Product
    const { data: productData, error } = await supabase
        .from('products')
        .select(`
            *,
            categories (name)
        `)
        .eq('slug', slug)
        .single();

    if (error || !productData) {
        return null;
    }

    // Map product
    const mappedProduct = {
        ...productData,
        category: productData.category || productData.categories?.name || "Uncategorized",
        media: productData.media || (productData.image ? [productData.image] : []),
        marketplace: {
            amazon: productData.amazon_link || null,
            flipkart: productData.flipkart_link || null,
            meesho: productData.meesho_link || null
        }
    };

    let relatedBlogs: any[] = [];

    // Fetch Related Blogs
    const relatedBlogIds = productData.alchemical_properties?.related_blogs || productData.related_blog_ids || [];

    if (relatedBlogIds.length > 0) {
        const { data: blogsData } = await supabase
            .from('blogs')
            .select('*')
            .in('id', relatedBlogIds);

        if (blogsData) {
            relatedBlogs = blogsData.map((b: any) => ({
                ...b,
                coverImage: b.image,
                readTime: "5 min" // static for now
            }));
        }
    }

    return { product: mappedProduct, relatedBlogs };
};

export const fetchRecommendedProducts = async (category: string, currentProductId: string) => {
    const supabase = await createClient();

    const { data: recommendedData } = await supabase
        .from('products')
        .select(`
            *,
            categories (name)
        `)
        .eq('status', 'Published')
        .neq('id', currentProductId)
        .eq('category', category)
        .limit(4);

    if (!recommendedData || recommendedData.length === 0) {
        // Fallback to latest products if category doesn't have enough
        const { data: latestData } = await supabase
            .from('products')
            .select(`
                *,
                categories (name)
            `)
            .eq('status', 'Published')
            .neq('id', currentProductId)
            .order('created_at', { ascending: false })
            .limit(4);

        return (latestData || []).map((p: any) => ({
            ...p,
            category: p.category || p.categories?.name || "Uncategorized"
        }));
    }

    return recommendedData.map((p: any) => ({
        ...p,
        category: p.category || p.categories?.name || "Uncategorized"
    }));
};

import { createServerClient } from '@supabase/ssr'
import { NextResponse, type NextRequest } from 'next/server'

export async function updateSession(request: NextRequest) {
    let supabaseResponse = NextResponse.next({
        request,
    })

    const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL!;
    const supabaseKey = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!;

    if (!supabaseUrl || !supabaseKey) {
        console.error("Middleware Error: Missing Supabase URL or Key");
        return supabaseResponse;
    }

    const supabase = createServerClient(
        supabaseUrl,
        supabaseKey,
        {
            cookies: {
                getAll() {
                    return request.cookies.getAll()
                },
                setAll(cookiesToSet) {
                    cookiesToSet.forEach(({ name, value, options }) => request.cookies.set(name, value))
                    supabaseResponse = NextResponse.next({
                        request,
                    })
                    cookiesToSet.forEach(({ name, value, options }) =>
                        supabaseResponse.cookies.set(name, value, options)
                    )
                },
            },
        }
    )

    // IMPORTANT: Avoid writing any logic between createServerClient and
    // supabase.auth.getUser(). A simple mistake could make it very hard to debug
    // issues with users being randomly logged out.

    const {
        data: { user },
    } = await supabase.auth.getUser()

    // PROTECTED ADMIN ROUTES
    if (request.nextUrl.pathname.startsWith('/admin') && !request.nextUrl.pathname.startsWith('/admin-login')) {
        // 1. Check if user is logged in
        if (!user) {
            console.log("Middleware: No user for admin route. Redirecting to login.");
            const url = request.nextUrl.clone()
            url.pathname = '/admin-login'
            return NextResponse.redirect(url)
        }

        // 2. Check if user is actually an admin
        const { data: profile, error } = await supabase
            .from('profiles')
            .select('role')
            .eq('id', user.id)
            .single()

        console.log(`Middleware Debug: Path=${request.nextUrl.pathname}, UserID=${user.id}, Role=${profile?.role}, Error=${error?.message}`);

        if (profile?.role !== 'admin') {
            console.log("Middleware: User is not admin. Redirecting to home.");
            // If customer tries to access admin, kick them out
            const url = request.nextUrl.clone()
            url.pathname = '/'
            return NextResponse.redirect(url)
        }
    }

    // OPTIONAL: Protect other routes if needed (e.g. account)

    return supabaseResponse
}

import { Node, mergeAttributes } from '@tiptap/core';

export interface VideoOptions {
    width: number;
    height: number;
    HTMLAttributes: Record<string, any>;
}

declare module '@tiptap/core' {
    interface Commands<ReturnType> {
        video: {
            /**
             * Set a video node
             */
            setVideo: (options: { src: string }) => ReturnType;
        };
    }
}

export const VideoExtension = Node.create<VideoOptions>({
    name: 'video',

    addOptions() {
        return {
            width: 640,
            height: 480,
            HTMLAttributes: {
                controls: true,
                class: 'w-full aspect-video rounded-xl shadow-xl bg-black',
            },
        };
    },

    group: 'block',

    draggable: true,

    addAttributes() {
        return {
            src: {
                default: null,
            },
            width: {
                default: this.options.width,
            },
            height: {
                default: this.options.height,
            },
        };
    },

    parseHTML() {
        return [
            {
                tag: 'video',
            },
        ];
    },

    renderHTML({ HTMLAttributes }) {
        return ['video', mergeAttributes(this.options.HTMLAttributes, HTMLAttributes)];
    },

    addCommands() {
        return {
            setVideo:
                (options) =>
                    ({ commands }) => {
                        return commands.insertContent({
                            type: this.name,
                            attrs: options,
                        });
                    },
        };
    },
});

